const baseResume    = body.baseResume    || '';
const recipientEmail = body.recipientEmail || 'rvnegi786@gmail.com';
const companyName   = body.companyName   || 'the company';

if (!jobDescription) throw new Error('jobDescription is required in the request body');
if (!baseResume)     throw new Error('baseResume is required in the request body');

