return {
  resumeText,
  recipientEmail,
  companyName,
  emailBody,
  subject: `📄 Resume for ${companyName} — ${dateStr} | ResumeForge AI`,
  parsedSections: sections,
  name,
  contactLine
};

const PDFDocument = require('pdfkit');

const meta = $('Prepare Doc Content').item.json;
const resumeText = meta.resumeText || '';
const recipientEmail = meta.recipientEmail || 'rvnegi786@gmail.com';
const subject = meta.subject || 'Your Tailored Resume';
const emailBody = meta.emailBody || '';
const companyName = meta.companyName || '';

// ─── Parse resume text into sections ───────────────────────────────────────
function cleanText(t) {
  return (t || '').replace(/```[a-z]*\n?/gi, '').replace(/```/g, '').trim();
}
function stripBold(s) {
  return String(s).replace(/\*\*(.*?)\*\*/g, '$1');
}

const SECTIONS = [
  'PROFESSIONAL SUMMARY', 'TECHNICAL SKILLS', 'PROFESSIONAL EXPERIENCE',
  'WORK EXPERIENCE', 'EXPERIENCE', 'PROJECTS', 'AWARDS', 'EDUCATION', 'SKILLS'
];

const rawLines = cleanText(resumeText).split('\n');
let nameStr = '', contactStr = '', linksStr = '';
let sections = {}, currentSection = '', sectionContent = [];

for (let i = 0; i < rawLines.length; i++) {
  const line = rawLines[i].trim();
  if (!line) continue;
  if (i === 0) { nameStr = stripBold(line); continue; }
  if (i === 1) { contactStr = stripBold(line).replace(/\|/g, '  |  '); continue; }
  if (i === 2 && (line.toLowerCase().includes('linkedin') || line.toLowerCase().includes('github'))) {
    linksStr = stripBold(line); continue;
  }
  const upper = line.toUpperCase();
  const matchedSection = SECTIONS.find(s => upper.startsWith(s));
  if (matchedSection) {
    if (currentSection) sections[currentSection] = [...sectionContent];
    currentSection = matchedSection;
    sectionContent = [];
  } else {
    if (currentSection) sectionContent.push(rawLines[i]);
  }
}
if (currentSection) sections[currentSection] = [...sectionContent];

// ─── PDF Generation ─────────────────────────────────────────────────────────
const pdfBuffer = await new Promise((resolve, reject) => {
  const doc = new PDFDocument({
    size: 'A4',
    margins: { top: 44, bottom: 44, left: 52, right: 52 }
  });

  const chunks = [];
  doc.on('data', chunk => chunks.push(chunk));
  doc.on('end', () => resolve(Buffer.concat(chunks)));
  doc.on('error', reject);

  const pageWidth = doc.page.width;
  const LEFT = 52;
  const RIGHT = pageWidth - 52;
  const contentWidth = RIGHT - LEFT;

  // ── Colour palette ──────────────────────────────────────────────────────
  const COLOR_NAME    = '#1a1a2e';
  const COLOR_SECTION = '#2d2a4a';
  const COLOR_RULE    = '#7c3aed';
  const COLOR_BODY    = '#2c2c3e';
  const COLOR_MUTED   = '#6b6880';

  // ── Helpers ──────────────────────────────────────────────────────────────
  function drawSectionTitle(title) {
    doc.moveDown(0.55);
    doc
      .font('Helvetica-Bold')
      .fontSize(10.5)
      .fillColor(COLOR_SECTION)
      .text(title.charAt(0).toUpperCase() + title.slice(1).toLowerCase(), LEFT, doc.y, { width: contentWidth });
    const lineY = doc.y + 2;
    doc
      .moveTo(LEFT, lineY)
      .lineTo(RIGHT, lineY)
      .lineWidth(0.8)
      .strokeColor(COLOR_RULE)
      .stroke();
    doc.moveDown(0.45);
  }

  function drawRowWithDate(leftText, rightText, bold = false) {
    const y = doc.y;
    const dateWidth = 115;
    const textWidth = contentWidth - dateWidth;
    if (bold) {
      doc.font('Helvetica-Bold').fontSize(10).fillColor(COLOR_BODY);
    } else {
      doc.font('Helvetica').fontSize(10).fillColor(COLOR_BODY);
    }
    doc.text(stripBold(leftText), LEFT, y, { width: textWidth, lineBreak: false });
    doc.font('Helvetica-Oblique').fontSize(9).fillColor(COLOR_MUTED)
      .text(stripBold(rightText), LEFT + textWidth, y, { width: dateWidth, align: 'right', lineBreak: false });
    doc.moveDown(0.3);
  }

  function drawBullet(text) {
    const y = doc.y;
    doc.font('Helvetica').fontSize(9.5).fillColor(COLOR_BODY)
      .text('•', LEFT + 2, y, { width: 10, lineBreak: false });
    doc.text(stripBold(text.replace(/^[-•*]\s*/, '').trim()), LEFT + 14, y, { width: contentWidth - 14 });
    doc.moveDown(0.18);
  }

  function drawBody(text) {
    doc.font('Helvetica').fontSize(9.5).fillColor(COLOR_BODY)
      .text(stripBold(text), LEFT, doc.y, { width: contentWidth });
    doc.moveDown(0.18);
  }

  function drawSkillLine(line) {
    const colonIdx = line.indexOf(':');
    if (colonIdx > -1) {
      const label = stripBold(line.slice(0, colonIdx).trim());
      const value = stripBold(line.slice(colonIdx + 1).trim());
      const y = doc.y;
      doc.font('Helvetica-Bold').fontSize(9.5).fillColor(COLOR_BODY)
        .text(label + ':', LEFT, y, { continued: true })
        .font('Helvetica').fillColor(COLOR_BODY)
        .text(' ' + value, { width: contentWidth });
    } else {
      drawBody(line);
    }
    doc.moveDown(0.12);
  }

  function drawProjectLine(line) {
    const isBullet = line.trim().startsWith('•') || line.trim().startsWith('-');
    let content = isBullet ? line.trim().slice(1).trim() : line.trim();
    content = stripBold(content);

    const urlMatch = content.match(/\s+(https?:\/\/\S+|[\w.\-/]+\.(?:app|io|com|net|org|dev)\S*)$/);
    const url = urlMatch ? urlMatch[1] : '';
    const mainPart = url ? content.slice(0, content.lastIndexOf(url)).trim() : content;

    const dashIdx = mainPart.indexOf('—') > -1 ? mainPart.indexOf('—') :
                    mainPart.indexOf('|') > -1 ? mainPart.indexOf('|') : -1;

    if (dashIdx > -1 || url) {
      const projName = dashIdx > -1 ? mainPart.slice(0, dashIdx).trim() : mainPart;
      const tech = dashIdx > -1 ? mainPart.slice(dashIdx + 1).trim() : '';
      const y = doc.y;
      const urlWidth = url ? Math.min(url.replace(/^https?:\/\//, '').length * 5 + 10, 170) : 0;

      doc.font('Helvetica-Bold').fontSize(9.5).fillColor(COLOR_BODY)
        .text('• ' + projName, LEFT, y, { continued: tech ? true : false, lineBreak: false });
      if (tech) {
        doc.font('Helvetica').fontSize(9.5).fillColor(COLOR_MUTED)
          .text('  —  ' + tech, { continued: false, lineBreak: false });
      }
      if (url) {
        const displayUrl = url.replace(/^https?:\/\//, '');
        const textX = RIGHT - urlWidth;
        doc.font('Helvetica').fontSize(8).fillColor('#7c3aed')
          .text(displayUrl, textX, y, { width: urlWidth, align: 'right' });
        doc.rect(textX - 2, y - 1, urlWidth + 2, 11)
          .lineWidth(0.5).strokeColor('#7c3aed').stroke();
        doc.fillColor(COLOR_BODY);
      }
      doc.moveDown(0.28);
    } else {
      doc.font('Helvetica').fontSize(9.5).fillColor(COLOR_BODY)
        .text(content, LEFT + 14, doc.y, { width: contentWidth - 14 });
      doc.moveDown(0.15);
    }
  }

  // ── HEADER ──────────────────────────────────────────────────────────────
  doc.font('Helvetica-Bold').fontSize(17).fillColor(COLOR_NAME)
    .text(nameStr, LEFT, 44, { width: contentWidth, align: 'center' });
  doc.moveDown(0.25);

  doc.font('Helvetica').fontSize(9).fillColor(COLOR_MUTED)
    .text(contactStr, LEFT, doc.y, { width: contentWidth, align: 'center' });
  doc.moveDown(0.2);

  if (linksStr) {
    const links = linksStr.split('|').map(l => l.trim()).filter(Boolean);
    const linkText = links.join('  |  ');
    doc.font('Helvetica').fontSize(9).fillColor('#7c3aed')
      .text(linkText, LEFT, doc.y, { width: contentWidth, align: 'center' });
    doc.moveDown(0.5);
  }

  // thin rule under header
  doc.moveTo(LEFT, doc.y).lineTo(RIGHT, doc.y)
    .lineWidth(0.5).strokeColor('#d1cfe8').stroke();
  doc.moveDown(0.3);

  // ── PROFESSIONAL SUMMARY ─────────────────────────────────────────────────
  const summary = sections['PROFESSIONAL SUMMARY'] || [];
  if (summary.length) {
    drawSectionTitle('Professional Summary');
    summary.forEach(line => { if (line.trim()) drawBody(line); });
  }

  // ── TECHNICAL SKILLS ─────────────────────────────────────────────────────
  const skills = sections['TECHNICAL SKILLS'] || sections['SKILLS'] || [];
  if (skills.length) {
    drawSectionTitle('Technical Skills');
    skills.forEach(line => { if (line.trim()) drawSkillLine(line.trim()); });
  }

  // ── PROFESSIONAL EXPERIENCE ──────────────────────────────────────────────
  const exp = sections['PROFESSIONAL EXPERIENCE'] || sections['WORK EXPERIENCE'] || sections['EXPERIENCE'] || [];
  if (exp.length) {
    drawSectionTitle('Professional Experience');
    exp.forEach(line => {
      const trimmed = line.trim();
      if (!trimmed) return;
      if ((trimmed.includes('|') || trimmed.includes('—')) &&
          (trimmed.includes('20') || trimmed.toLowerCase().includes('present'))) {
        const sep = trimmed.includes('|') ? '|' : '—';
        const parts = trimmed.split(sep);
        const left = parts.slice(0, -1).join(sep).trim();
        const date = parts[parts.length - 1].trim();
        drawRowWithDate(left, date, true);
      } else if (trimmed.startsWith('•') || trimmed.startsWith('-') || trimmed.startsWith('*')) {
        drawBullet(trimmed);
      } else {
        doc.font('Helvetica').fontSize(9.5).fillColor(COLOR_MUTED)
          .text(stripBold(trimmed), LEFT, doc.y, { width: contentWidth });
        doc.moveDown(0.2);
      }
    });
  }

  // ── PROJECTS ─────────────────────────────────────────────────────────────
  const projects = sections['PROJECTS'] || [];
  if (projects.length) {
    drawSectionTitle('Projects');
    projects.forEach(line => { if (line.trim()) drawProjectLine(line); });
  }

  // ── AWARDS ───────────────────────────────────────────────────────────────
  const awards = sections['AWARDS'] || [];
  if (awards.length) {
    drawSectionTitle('Awards');
    awards.forEach(line => {
      const trimmed = line.trim();
      if (!trimmed) return;
      const clean = trimmed.replace(/^[-•*]\s*/, '').trim();
      if (clean.includes('|') || clean.includes('—')) {
        const sep = clean.includes('|') ? '|' : '—';
        const parts = clean.split(sep);
        drawRowWithDate(parts.slice(0,-1).join(sep).trim(), parts[parts.length-1].trim(), true);
      } else {
        drawBody(clean);
      }
    });
  }

  // ── EDUCATION ────────────────────────────────────────────────────────────
  const edu = sections['EDUCATION'] || [];
  if (edu.length) {
    drawSectionTitle('Education');
    edu.forEach(line => {
      const trimmed = line.trim();
      if (!trimmed) return;
      if (trimmed.includes('|') && trimmed.includes('20')) {
        const parts = trimmed.split('|');
        drawRowWithDate(parts.slice(0,-1).join('|').trim(), parts[parts.length-1].trim(), true);
      } else {
        drawBody(trimmed);
      }
    });
  }

  doc.end();
});

return {
  json: {
    recipientEmail,
    subject,
    emailBody
  },
  binary: {
    data: {
      data: pdfBuffer.toString('base64'),
      mimeType: 'application/pdf',
      fileName: `Resume_${companyName.replace(/\s+/g,'_') || 'Tailored'}.pdf`
    }
  }
};
